import kotlinx.browser.document
import org.w3c.dom.HTMLStyleElement

internal object XkcdFontFace {
    private const val STYLE_ID = "lets-plot-xkcd-humor-sans-font"

    private const val HUMOR_SANS_BASE64 = ""

    fun ensureInjected() {
        if (document.getElementById(STYLE_ID) != null) {
            return
        }

        val head = document.head ?: return
        val styleElement = document.createElement("style") as HTMLStyleElement
        styleElement.id = STYLE_ID
        styleElement.textContent = """
            @font-face {
                font-family: 'Humor Sans';
                src: local('Humor Sans'),
                     local('HumorSans-Regular'),
                     url('data:font/ttf;base64,$HUMOR_SANS_BASE64') format('truetype');
                font-style: normal;
                font-weight: 400;
                font-display: swap;
            }
        """.trimIndent()

        head.appendChild(styleElement)
    }
}
